import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.util.Scanner;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name:");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS
        HTMLEntityCodec htmlEncoder = ESAPI.encoder().getHTMLEntityCodec();
        String sanitizedInput = htmlEncoder.encodeForHTML(userInput);

        System.out.println("Hello, " + sanitizedInput + "!"); // Sanitized output

        scanner.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
